import { useState, useEffect } from "react";
import "./Recruitment.css";

function CreateLogin() {

  const [employees, setEmployees] = useState([]);
  const [users, setUsers] = useState([]);

  const [selectedEmp, setSelectedEmp] = useState("");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [designation, setDesignation] = useState("");

  /* =========================================
        LOAD EMPLOYEES + USERS (SAFE)
     ========================================= */
  useEffect(() => {
    const emp = JSON.parse(localStorage.getItem("employees")) || [];
    let usr = JSON.parse(localStorage.getItem("users")) || [];

    setEmployees(emp);

    // SAFETY CLEANUP
    const cleaned = usr.filter(
      u =>
        u &&
        u.name &&
        u.username &&
        u.role &&
        u.empId
    );

    // If cleanup removed junk → save back safely
    if (cleaned.length !== usr.length) {
      localStorage.setItem("users", JSON.stringify(cleaned));
      usr = cleaned;
    }

    setUsers(usr);
  }, []);

  /* =========================================
        SELECT EMPLOYEE → AUTO FILL
     ========================================= */
  const handleSelect = (id) => {
    setSelectedEmp(id);

    const emp = employees.find(e => String(e.id) === String(id));

    if (emp) {
      setDesignation(emp.designation || "");
      setUsername(emp.email || "");
    }
  };

  /* =========================================
        CREATE LOGIN
     ========================================= */
  const handleCreate = () => {
    if (!selectedEmp) return alert("Please select employee");
    if (!username.trim()) return alert("Enter username");
    if (!password.trim()) return alert("Enter password");

    const employee = employees.find(
      e => String(e.id) === String(selectedEmp)
    );

    // Prevent duplicate login
    const exists = users.some(u => u.empId === employee.id);
    if (exists) return alert("Login already created for this employee");

    const newUser = {
      empId: employee.id,
      name: `${employee.firstName} ${employee.lastName}`,
      username,
      password,
      role: designation || "Employee"
    };

    const updated = [...users, newUser];

    setUsers(updated);
    localStorage.setItem("users", JSON.stringify(updated));

    alert("Login Created Successfully");
    setPassword("");
  };

  return (
    <div className="designation-container">
      <h2>Create Login Credentials</h2>

      <div className="designation-form">

        {/* Select Employee */}
        <select
          value={selectedEmp}
          onChange={(e) => handleSelect(e.target.value)}
        >
          <option value="">Select Employee</option>

          {employees.map(emp => (
            <option key={emp.id} value={emp.id}>
              {emp.firstName} {emp.lastName}
            </option>
          ))}
        </select>

        {/* Designation */}
        <input
          type="text"
          value={designation}
          placeholder="Designation"
          disabled
        />

        {/* Username */}
        <input
          type="text"
          placeholder="Enter Username / Email"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />

        {/* Password */}
        <input
          type="text"
          placeholder="Enter Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <button onClick={handleCreate}>
          Create Login
        </button>
      </div>

      {/* USERS TABLE */}
      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Username</th>
            <th>Role</th>
          </tr>
        </thead>

        <tbody>
          {users.length === 0 ? (
            <tr>
              <td colSpan="4">No Users Created Yet</td>
            </tr>
          ) : (
            users.map((u, index) => (
              <tr key={u.empId}>
                <td>{index + 1}</td>
                <td>{u.name}</td>
                <td>{u.username}</td>
                <td>{u.role}</td>
              </tr>
            ))
          )}
        </tbody>
      </table>

    </div>
  );
}

export default CreateLogin;
